 15→/**
 16→ * Abandon training session API route.
 17→ * POST /api/training/{tenant}/abandon — T032
 18→ * Transitions an in-progress or in-remediation session to abandoned.
 19→ */
 20→
 21→import { generateEvidenceForSession } from "@/evidence/evidence-generator";
 22→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 23→import { logSessionAbandoned } from "@/training/audit";
 24→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 25→import { StateTransitionError, transitionSession } from "@/training/state-machine";
 26→import { NextResponse } from "next/server";
 27→
 28→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 29→  const { tenant: tenantSlug } = await params;
 30→  const tenantId = request.headers.get("x-tenant-id");
 31→  const employeeId = request.headers.get("x-employee-id");
 32→
 33→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 34→    return NextResponse.json(
 35→      { error: "unauthorized", message: "Not authenticated" },
 36→      { status: 401 },
 37→    );
 38→  }
 39→
 40→  // Initialise repositories per-request to avoid connection sharing
 41→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 42→  const sessionRepo = new SessionRepository(storage);
 43→
 44→  await storage.initialize();
 45→
 46→  try {
 47→    // 1. Find active session — 404 if none
 48→    const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 49→    if (!session) {
 50→      return NextResponse.json(
 51→        { error: "not_found", message: "No active training session found" },
 52→        { status: 404 },
 53→      );
 54→    }
 55→
 56→    // 2. Guard: session must be in-progress or in-remediation
 57→    if (session.status !== "in-progress" && session.status !== "in-remediation") {
 58→      return NextResponse.json(
 59→        {
 60→          error: "conflict",
 61→          message: `Session is in '${session.status}' state, expected 'in-progress' or 'in-remediation'`,
 62→        },
 63→        { status: 409 },
 64→      );
 65→    }
 66→
 67→    // 3. Validate state transition
 68→    let nextStatus: ReturnType<typeof transitionSession>;
 69→    try {
 70→      nextStatus = transitionSession(session.status, "session-abandoned");
 71→    } catch (err) {
 72→      if (err instanceof StateTransitionError) {
 73→        return NextResponse.json({ error: "conflict", message: err.message }, { status: 409 });
 74→      }
 75→      throw err;
 76→    }
 77→
 78→    // 4. Update session to abandoned with completedAt
 79→    const now = new Date().toISOString();
 80→    let updatedSession: Awaited<ReturnType<typeof sessionRepo.updateSession>>;
 81→    try {
 82→      updatedSession = await sessionRepo.updateSession(
 83→        tenantId,
 84→        session.id,
 85→        {
 86→          status: nextStatus,
 87→          completedAt: now,
 88→        },
 89→        session.version,
 90→      );
 91→    } catch (err) {
 92→      if (err instanceof VersionConflictError) {
 93→        return NextResponse.json(
 94→          { error: "conflict", message: "Session was modified by another request" },
 95→          { status: 409 },
 96→        );
 97→      }
 98→      throw err;
 99→    }
100→
101→    // 5. Count modules completed (status "scored")
102→    const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
103→    const modulesCompleted = modules.filter((m) => m.status === "scored").length;
104→    const totalModules = modules.length;
105→
106→    // 6. Log audit event
107→    await logSessionAbandoned(
108→      storage,
109→      tenantId,
110→      employeeId,
111→      session.id,
112→      session.attemptNumber,
113→      modulesCompleted,
114→      totalModules,
115→    );
116→
117→    // 7. Fire-and-forget evidence generation
118→    generateEvidenceForSession(storage, tenantId, session.id).catch((err) =>
119→      console.error("Evidence generation failed:", err),
120→    );
121→
122→    // 8. Return 200 with updated session
123→    return NextResponse.json({ session: updatedSession }, { status: 200 });
124→  } finally {
125→    await storage.close();
126→  }
127→}
128→

