 15→/**
 16→ * Evaluation API route.
 17→ * POST /api/training/{tenant}/evaluate
 18→ * Computes the final pass/fail decision for a training session in `evaluating` state.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { generateEvidenceForSession } from "@/evidence/evidence-generator";
 23→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 24→import { logEvaluationCompleted, logSessionExhausted } from "@/training/audit";
 25→import { computeAggregateScore, identifyWeakAreas, isPassing } from "@/training/score-calculator";
 26→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 27→import { StateTransitionError, transitionSession } from "@/training/state-machine";
 28→import { NextResponse } from "next/server";
 29→
 30→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 31→  const { tenant: tenantSlug } = await params;
 32→  const tenantId = request.headers.get("x-tenant-id");
 33→  const employeeId = request.headers.get("x-employee-id");
 34→
 35→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 36→    return NextResponse.json(
 37→      { error: "unauthorized", message: "Not authenticated" },
 38→      { status: 401 },
 39→    );
 40→  }
 41→
 42→  // Initialise repositories per-request to avoid connection sharing
 43→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 44→  const sessionRepo = new SessionRepository(storage);
 45→
 46→  await storage.initialize();
 47→
 48→  try {
 49→    // Find active session
 50→    const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 51→    if (!session) {
 52→      return NextResponse.json(
 53→        { error: "not_found", message: "No active training session found" },
 54→        { status: 404 },
 55→      );
 56→    }
 57→
 58→    // Guard: session must be in evaluating state
 59→    if (session.status !== "evaluating") {
 60→      return NextResponse.json(
 61→        {
 62→          error: "conflict",
 63→          message: `Session is in '${session.status}' state, expected 'evaluating'`,
 64→        },
 65→        { status: 409 },
 66→      );
 67→    }
 68→
 69→    // Find all modules
 70→    const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
 71→
 72→    // Extract module scores — all must be non-null before computing aggregate
 73→    const rawScores = modules.map((m) => m.moduleScore);
 74→    if (rawScores.some((s) => s === null || s === undefined)) {
 75→      return NextResponse.json(
 76→        { error: "conflict", message: "Not all modules have been scored" },
 77→        { status: 409 },
 78→      );
 79→    }
 80→    const moduleScores = rawScores as number[];
 81→
 82→    // Compute aggregate score
 83→    const aggregateScore = computeAggregateScore(moduleScores) ?? 0;
 84→
 85→    // Get tenant training config
 86→    const snapshot = getSnapshot();
 87→    const tenant = snapshot?.tenants.get(tenantId);
 88→    const trainingConfig = tenant?.settings?.training;
 89→    const passThreshold = trainingConfig?.passThreshold ?? 0.7;
 90→    const maxAttempts = trainingConfig?.maxAttempts ?? 3;
 91→
 92→    const now = new Date().toISOString();
 93→    let nextAction: "complete" | "remediation-available" | "exhausted";
 94→    let passed: boolean;
 95→    let newStatus: "passed" | "failed" | "exhausted";
 96→    let completedAt: string | null = null;
 97→    let weakAreas: string[] | undefined;
 98→
 99→    if (isPassing(aggregateScore, passThreshold)) {
100→      // Pass
101→      passed = true;
102→      newStatus = "passed";
103→      nextAction = "complete";
104→      completedAt = now;
105→    } else if (session.attemptNumber < maxAttempts) {
106→      // Failed with attempts remaining
107→      passed = false;
108→      newStatus = "failed";
109→      nextAction = "remediation-available";
110→      weakAreas = identifyWeakAreas(
111→        modules.map((m) => ({ topicArea: m.topicArea, moduleScore: m.moduleScore as number })),
112→        passThreshold,
113→      );
114→    } else {
115→      // Failed and exhausted all attempts
116→      passed = false;
117→      newStatus = "exhausted";
118→      nextAction = "exhausted";
119→      completedAt = now;
120→    }
121→
122→    // Transition session state
123→    try {
124→      transitionSession(
125→        session.status,
126→        `evaluation-${newStatus}` as Parameters<typeof transitionSession>[1],
127→      );
128→    } catch (err) {
129→      if (err instanceof StateTransitionError) {
130→        return NextResponse.json({ error: "conflict", message: err.message }, { status: 409 });
131→      }
132→      throw err;
133→    }
134→
135→    // Update session
136→    const updateData: Parameters<typeof sessionRepo.updateSession>[2] = {
137→      status: newStatus,
138→      aggregateScore,
139→      ...(weakAreas !== undefined ? { weakAreas } : {}),
140→      ...(completedAt !== null ? { completedAt } : {}),
141→    };
142→
143→    try {
144→      await sessionRepo.updateSession(tenantId, session.id, updateData, session.version);
145→    } catch (err) {
146→      if (err instanceof VersionConflictError) {
147→        return NextResponse.json(
148→          { error: "conflict", message: "Session was modified by another request" },
149→          { status: 409 },
150→        );
151→      }
152→      throw err;
153→    }
154→
155→    // Audit logging
156→    await logEvaluationCompleted(
157→      storage,
158→      tenantId,
159→      employeeId,
160→      session.id,
161→      session.attemptNumber,
162→      aggregateScore,
163→      passed,
164→    );
165→
166→    if (newStatus === "exhausted") {
167→      await logSessionExhausted(
168→        storage,
169→        tenantId,
170→        employeeId,
171→        session.id,
172→        aggregateScore,
173→        session.attemptNumber,
174→      );
175→    }
176→
177→    // Fire-and-forget evidence generation for terminal states
178→    if (newStatus === "passed" || newStatus === "exhausted") {
179→      generateEvidenceForSession(storage, tenantId, session.id).catch((err) =>
180→        console.error("Evidence generation failed:", err),
181→      );
182→    }
183→
184→    return NextResponse.json(
185→      {
186→        sessionId: session.id,
187→        aggregateScore,
188→        passed,
189→        attemptNumber: session.attemptNumber,
190→        ...(weakAreas !== undefined ? { weakAreas } : {}),
191→        nextAction,
192→      },
193→      { status: 200 },
194→    );
195→  } finally {
196→    await storage.close();
197→  }
198→}
