 15→/**
 16→ * Evidence generator — assembles a tamper-evident training evidence record
 17→ * from a completed (terminal) training session and its modules.
 18→ */
 19→
 20→import { getSnapshot } from "../config/index.js";
 21→import type { StorageAdapter } from "../storage/adapter.js";
 22→import type { TrainingModule, TrainingSession } from "../training/schemas.js";
 23→import { SessionRepository } from "../training/session-repository.js";
 24→import { EvidenceRepository } from "./evidence-repository.js";
 25→import { computeContentHash } from "./hash.js";
 26→import type { EvidenceBody, ModuleEvidence, TrainingEvidence } from "./schemas.js";
 27→
 28→// ---------------------------------------------------------------------------
 29→// Constants
 30→// ---------------------------------------------------------------------------
 31→
 32→const TERMINAL_STATUSES = new Set(["passed", "exhausted", "abandoned"]);
 33→const CURRENT_SCHEMA_VERSION = 1;
 34→const SESSIONS_COLLECTION = "training_sessions";
 35→
 36→// ---------------------------------------------------------------------------
 37→// Public API
 38→// ---------------------------------------------------------------------------
 39→
 40→/**
 41→ * Generate an immutable evidence record for a terminal training session.
 42→ *
 43→ * Idempotent: if evidence already exists for the session, returns the existing record.
 44→ * Throws if the session is not in a terminal state (passed, exhausted, abandoned).
 45→ */
 46→export async function generateEvidenceForSession(
 47→  storage: StorageAdapter,
 48→  tenantId: string,
 49→  sessionId: string,
 50→): Promise<TrainingEvidence> {
 51→  const sessionRepo = new SessionRepository(storage);
 52→  const evidenceRepo = new EvidenceRepository(storage);
 53→
 54→  // 1. Load session
 55→  const session = await storage.findById<TrainingSession>(tenantId, SESSIONS_COLLECTION, sessionId);
 56→
 57→  if (!session) {
 58→    throw new Error(`Session '${sessionId}' not found`);
 59→  }
 60→
 61→  if (!TERMINAL_STATUSES.has(session.status)) {
 62→    throw new Error(
 63→      `Session '${sessionId}' is in '${session.status}' state, expected terminal state (passed, exhausted, or abandoned)`,
 64→    );
 65→  }
 66→
 67→  // 2. Idempotency check — return existing evidence if already generated
 68→  const existing = await evidenceRepo.findBySessionId(tenantId, sessionId);
 69→  if (existing) {
 70→    return existing;
 71→  }
 72→
 73→  // 3. Load modules
 74→  const modules = await sessionRepo.findModulesBySession(tenantId, sessionId);
 75→
 76→  // 4. Resolve tenant config for thresholds
 77→  const snapshot = getSnapshot();
 78→  const tenant = snapshot?.tenants.get(tenantId);
 79→  const passThreshold = tenant?.settings?.training?.passThreshold ?? 0.7;
 80→  const maxAttempts = tenant?.settings?.training?.maxAttempts ?? 3;
 81→
 82→  // 5. Assemble the evidence body
 83→  const evidenceBody: EvidenceBody = {
 84→    session: {
 85→      sessionId: session.id,
 86→      employeeId: session.employeeId,
 87→      tenantId: session.tenantId,
 88→      attemptNumber: session.attemptNumber,
 89→      totalAttempts: session.attemptNumber,
 90→      status: session.status as "passed" | "exhausted" | "abandoned",
 91→      createdAt: session.createdAt,
 92→      completedAt: session.completedAt,
 93→    },
 94→    policyAttestation: {
 95→      configHash: session.configHash,
 96→      roleProfileId: session.roleProfileId,
 97→      roleProfileVersion: session.roleProfileVersion,
 98→      appVersion: session.appVersion,
 99→      passThreshold,
100→      maxAttempts,
101→    },
102→    modules: modules.map((m) => buildModuleEvidence(m)),
103→    outcome: {
104→      aggregateScore: session.aggregateScore,
105→      passed: session.status === "passed" ? true : session.status === "abandoned" ? null : false,
106→      passThreshold,
107→      weakAreas: session.weakAreas,
108→      moduleScores: modules.map((m) => ({
109→        moduleIndex: m.moduleIndex,
110→        title: m.title,
111→        score: m.moduleScore,
112→      })),
113→    },
114→  };
115→
116→  // 6. Compute content hash for tamper detection
117→  const contentHash = computeContentHash(evidenceBody as unknown as Record<string, unknown>);
118→
119→  // 7. Persist the evidence record
120→  const record = await evidenceRepo.create(tenantId, {
121→    tenantId,
122→    sessionId: session.id,
123→    employeeId: session.employeeId,
124→    schemaVersion: CURRENT_SCHEMA_VERSION,
125→    evidence: evidenceBody,
126→    contentHash,
127→    generatedAt: new Date().toISOString(),
128→  });
129→
130→  return record;
131→}
132→
133→// ---------------------------------------------------------------------------
134→// Internal helpers
135→// ---------------------------------------------------------------------------
136→
137→/**
138→ * Build a client-safe module evidence record.
139→ * Strips `correct` from options and `rubric` from scenarios/questions.
140→ */
141→function buildModuleEvidence(module: TrainingModule): ModuleEvidence {
142→  const scenarios = module.content?.scenarios ?? [];
143→  const quizQuestions = module.content?.quiz?.questions ?? [];
144→
145→  return {
146→    moduleIndex: module.moduleIndex,
147→    title: module.title,
148→    topicArea: module.topicArea,
149→    moduleScore: module.moduleScore,
150→    scenarios: scenarios.map((s) => {
151→      const response = module.scenarioResponses.find((r) => r.scenarioId === s.id);
152→      return {
153→        scenarioId: s.id,
154→        narrative: s.narrative,
155→        responseType: s.responseType,
156→        options: s.options?.map((o) => ({ key: o.key, text: o.text })),
157→        employeeAnswer: {
158→          selectedOption: response?.selectedOption,
159→          freeTextResponse: response?.freeTextResponse,
160→          score: response?.score ?? 0,
161→          llmRationale: response?.llmRationale,
162→          submittedAt: response?.submittedAt ?? new Date().toISOString(),
163→        },
164→      };
165→    }),
166→    quizQuestions: quizQuestions.map((q) => {
167→      const answer = module.quizAnswers.find((a) => a.questionId === q.id);
168→      return {
169→        questionId: q.id,
170→        questionText: q.text,
171→        responseType: q.responseType,
172→        options: q.options?.map((o) => ({ key: o.key, text: o.text })),
173→        employeeAnswer: {
174→          selectedOption: answer?.selectedOption,
175→          freeTextResponse: answer?.freeTextResponse,
176→          score: answer?.score ?? 0,
177→          llmRationale: answer?.llmRationale,
178→          submittedAt: answer?.submittedAt ?? new Date().toISOString(),
179→        },
180→      };
181→    }),
182→    completedAt: module.status === "scored" ? module.updatedAt : null,
183→  };
184→}
