15→/**
16→ * Manual evidence generation API route.
17→ * POST /api/training/{tenant}/evidence/{sessionId}/generate
18→ * Generates (or returns existing) evidence for a terminal training session.
19→ */
20→
21→import { generateEvidenceForSession } from "@/evidence/evidence-generator";
22→import { EvidenceRepository } from "@/evidence/evidence-repository";
23→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
24→import { NextResponse } from "next/server";
25→
26→const TERMINAL_STATUSES = new Set(["passed", "exhausted", "abandoned"]);
27→
28→export async function POST(
29→  request: Request,
30→  { params }: { params: Promise<{ tenant: string; sessionId: string }> },
31→) {
32→  const { tenant: tenantSlug, sessionId } = await params;
33→  const tenantId = request.headers.get("x-tenant-id");
34→  const employeeId = request.headers.get("x-employee-id");
35→
36→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
37→    return NextResponse.json(
38→      { error: "unauthorized", message: "Not authenticated" },
39→      { status: 401 },
40→    );
41→  }
42→
43→  const role = request.headers.get("x-employee-role") ?? "employee";
44→  if (role === "employee") {
45→    return NextResponse.json(
46→      { error: "forbidden", message: "Admin access required" },
47→      { status: 403 },
48→    );
49→  }
50→
51→  const storage = new SQLiteAdapter({
52→    dbPath: process.env.DB_PATH ?? "data/jem.db",
53→  });
54→  await storage.initialize();
55→
56→  try {
57→    // Check session exists and is in terminal state
58→    const session = await storage.findById(tenantId, "training_sessions", sessionId);
59→    if (!session) {
60→      return NextResponse.json(
61→        { error: "not_found", message: "Session not found" },
62→        { status: 404 },
63→      );
64→    }
65→    if (!TERMINAL_STATUSES.has((session as Record<string, unknown>).status as string)) {
66→      return NextResponse.json(
67→        { error: "conflict", message: "Session is not in a terminal state" },
68→        { status: 409 },
69→      );
70→    }
71→
72→    // Check if evidence already exists (idempotent)
73→    const evidenceRepo = new EvidenceRepository(storage);
74→    const existing = await evidenceRepo.findBySessionId(tenantId, sessionId);
75→    if (existing) {
76→      return NextResponse.json(existing, { status: 200 });
77→    }
78→
79→    // Generate evidence (awaited, not fire-and-forget)
80→    const evidence = await generateEvidenceForSession(storage, tenantId, sessionId);
81→    return NextResponse.json(evidence, { status: 201 });
82→  } finally {
83→    await storage.close();
84→  }
85→}
