 40→/**
 41→ * Generate an immutable evidence record for a terminal training session.
 42→ *
 43→ * Creates and manages its own storage connection so it is safe to call as a
 44→ * fire-and-forget background task without sharing a connection that may be
 45→ * closed by the caller.
 46→ *
 47→ * Idempotent: if evidence already exists for the session, returns the existing record.
 48→ * Throws if the session is not in a terminal state (passed, exhausted, abandoned).
 49→ */
 50→export async function generateEvidenceForSession(
 51→  tenantId: string,
 52→  sessionId: string,
 53→  dbPath?: string,
 54→): Promise<TrainingEvidence> {
 55→  const storage = new SQLiteAdapter({ dbPath: dbPath ?? process.env.DB_PATH ?? "data/jem.db" });
 56→  await storage.initialize();
 57→
 58→  try {
 59→    const sessionRepo = new SessionRepository(storage);
 60→    const evidenceRepo = new EvidenceRepository(storage);
 61→
 62→    // 1. Load session
 63→    const session = await storage.findById<TrainingSession>(
 64→      tenantId,
 65→      SESSIONS_COLLECTION,
 66→      sessionId,
 67→    );
 68→
 69→    if (!session) {
 70→      throw new Error(`Session '${sessionId}' not found`);
 71→    }
 72→
 73→    if (!TERMINAL_STATUSES.has(session.status)) {
 74→      throw new Error(
 75→        `Session '${sessionId}' is in '${session.status}' state, expected terminal state (passed, exhausted, or abandoned)`,
 76→      );
 77→    }
 78→
 79→    // 2. Idempotency check — return existing evidence if already generated
 80→    const existing = await evidenceRepo.findBySessionId(tenantId, sessionId);
 81→    if (existing) {
 82→      return existing;
 83→    }
 84→
 85→    // 3. Load modules
 86→    const modules = await sessionRepo.findModulesBySession(tenantId, sessionId);
 87→
 88→    // 4. Resolve tenant config for thresholds
 89→    const snapshot = getSnapshot();
 90→    const tenant = snapshot?.tenants.get(tenantId);
 91→    const passThreshold = tenant?.settings?.training?.passThreshold ?? 0.7;
 92→    const maxAttempts = tenant?.settings?.training?.maxAttempts ?? 3;
 93→
 94→    // 5. Assemble the evidence body
 95→    const evidenceBody: EvidenceBody = {
 96→      session: {
 97→        sessionId: session.id,
 98→        employeeId: session.employeeId,
 99→        tenantId: session.tenantId,
100→        attemptNumber: session.attemptNumber,
101→        totalAttempts: session.attemptNumber,
102→        status: session.status as "passed" | "exhausted" | "abandoned",
103→        createdAt: session.createdAt,
104→        completedAt: session.completedAt,
105→      },
106→      policyAttestation: {
107→        configHash: session.configHash,
108→        roleProfileId: session.roleProfileId,
109→        roleProfileVersion: session.roleProfileVersion,
110→        appVersion: session.appVersion,
111→        passThreshold,
112→        maxAttempts,
113→      },
114→      modules: modules.map((m) => buildModuleEvidence(m)),
115→      outcome: {
116→        aggregateScore: session.aggregateScore,
117→        passed: session.status === "passed" ? true : session.status === "abandoned" ? null : false,
118→        passThreshold,
119→        weakAreas: session.weakAreas,
120→        moduleScores: modules.map((m) => ({
121→          moduleIndex: m.moduleIndex,
122→          title: m.title,
123→          score: m.moduleScore,
124→        })),
125→      },
126→    };
127→
128→    // 6. Compute content hash for tamper detection
129→    const contentHash = computeContentHash(evidenceBody as unknown as Record<string, unknown>);
130→
131→    // 7. Persist the evidence record
132→    const record = await evidenceRepo.create(tenantId, {
133→      tenantId,
134→      sessionId: session.id,
135→      employeeId: session.employeeId,
136→      schemaVersion: CURRENT_SCHEMA_VERSION,
137→      evidence: evidenceBody,
138→      contentHash,
139→      generatedAt: new Date().toISOString(),
140→    });
141→
142→    return record;
143→  } finally {
144→    await storage.close();
145→  }
146→}
147→
148→// ---------------------------------------------------------------------------
149→// Internal helpers
150→// ---------------------------------------------------------------------------
151→
152→/**
153→ * Build a client-safe module evidence record.
154→ * Strips `correct` from options and `rubric` from scenarios/questions.
155→ */
156→function buildModuleEvidence(module: TrainingModule): ModuleEvidence {
157→  const scenarios = module.content?.scenarios ?? [];
158→  const quizQuestions = module.content?.quiz?.questions ?? [];
159→
160→  return {
161→    moduleIndex: module.moduleIndex,
162→    title: module.title,
163→    topicArea: module.topicArea,
164→    moduleScore: module.moduleScore,
165→    scenarios: scenarios.map((s) => {
166→      const response = module.scenarioResponses.find((r) => r.scenarioId === s.id);
167→      return {
168→        scenarioId: s.id,
169→        narrative: s.narrative,
170→        responseType: s.responseType,
171→        options: s.options?.map((o) => ({ key: o.key, text: o.text })),
172→        employeeAnswer: {
173→          selectedOption: response?.selectedOption,
174→          freeTextResponse: response?.freeTextResponse,
175→          score: response?.score ?? 0,
176→          llmRationale: response?.llmRationale,
177→          submittedAt: response?.submittedAt ?? module.updatedAt ?? module.createdAt,
178→        },
179→      };
180→    }),
181→    quizQuestions: quizQuestions.map((q) => {
182→      const answer = module.quizAnswers.find((a) => a.questionId === q.id);
183→      return {
184→        questionId: q.id,
185→        questionText: q.text,
186→        responseType: q.responseType,
187→        options: q.options?.map((o) => ({ key: o.key, text: o.text })),
188→        employeeAnswer: {
189→          selectedOption: answer?.selectedOption,
190→          freeTextResponse: answer?.freeTextResponse,
191→          score: answer?.score ?? 0,
192→          llmRationale: answer?.llmRationale,
193→          submittedAt: answer?.submittedAt ?? module.updatedAt ?? module.createdAt,
194→        },
195→      };
196→    }),
197→    completedAt: module.status === "scored" ? module.updatedAt : null,
198→  };
199→}
